import React, { useState } from 'react';

const SignUp = () => {
  const [formData, setFormData] = useState({
    nombre: '',
    email: '',
    contraseña: '',
    confirmarContraseña: ''
  });

  const [mensaje, setMensaje] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.nombre || !formData.email || !formData.contraseña || !formData.confirmarContraseña) {
      setMensaje('Por favor completa todos los campos');
      return;
    }

    if (formData.contraseña !== formData.confirmarContraseña) {
      setMensaje('Las contraseñas no coinciden');
      return;
    }

    setMensaje(`¡Registro exitoso! Bienvenido ${formData.nombre}`);
    setFormData({
      nombre: '',
      email: '',
      contraseña: '',
      confirmarContraseña: ''
    });
  };

  return (
    <div style={{ padding: '40px', maxWidth: '500px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
      <h1>Crear Cuenta</h1>
      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
            Nombre Completo:
          </label>
          <input
            type="text"
            name="nombre"
            value={formData.nombre}
            onChange={handleChange}
            style={{
              width: '100%',
              padding: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
              boxSizing: 'border-box',
              fontSize: '14px'
            }}
            placeholder="Tu nombre completo"
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
            Email:
          </label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            style={{
              width: '100%',
              padding: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
              boxSizing: 'border-box',
              fontSize: '14px'
            }}
            placeholder="tu@email.com"
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
            Contraseña:
          </label>
          <input
            type="password"
            name="contraseña"
            value={formData.contraseña}
            onChange={handleChange}
            style={{
              width: '100%',
              padding: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
              boxSizing: 'border-box',
              fontSize: '14px'
            }}
            placeholder="Ingresa tu contraseña"
          />
        </div>

        <div style={{ marginBottom: '20px' }}>
          <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
            Confirmar Contraseña:
          </label>
          <input
            type="password"
            name="confirmarContraseña"
            value={formData.confirmarContraseña}
            onChange={handleChange}
            style={{
              width: '100%',
              padding: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
              boxSizing: 'border-box',
              fontSize: '14px'
            }}
            placeholder="Confirma tu contraseña"
          />
        </div>

        <button
          type="submit"
          style={{
            width: '100%',
            padding: '12px',
            backgroundColor: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: 'pointer',
            marginBottom: '15px'
          }}
        >
          Registrarse
        </button>

        <a
          href="/landing"
          style={{
            display: 'block',
            textAlign: 'center',
            color: '#007bff',
            textDecoration: 'none',
            fontSize: '14px'
          }}
        >
          Volver a la página principal
        </a>
      </form>

      {mensaje && (
        <div
          style={{
            marginTop: '20px',
            padding: '15px',
            backgroundColor: mensaje.includes('exitoso') ? '#d4edda' : '#f8d7da',
            color: mensaje.includes('exitoso') ? '#155724' : '#721c24',
            borderRadius: '4px',
            border: `1px solid ${mensaje.includes('exitoso') ? '#c3e6cb' : '#f5c6cb'}`
          }}
        >
          {mensaje}
        </div>
      )}
    </div>
  );
};

export default SignUp;
